components.DocumentReviewFlow:
export default function DocumentReviewFlow() {
  const [clients, setClients] = useState([]);
  const [clientId, setClientId] = useState("");
  const [client, setClient] = useState(null);
  const [docs, setDocs] = useState([]);
  const [loadingClient, setLoadingClient] = useState(false);
  const [actions, setActions] = useState({});
  const [notes, setNotes] = useState({});
  const [phases, setPhases] = useState({});

  useEffect(() => {
    tools.host_listClients({}).then((r) => setClients(r.data || []));
  }, []);

  useEffect(() => {
    if (!clientId) { setClient(null); setDocs([]); return; }
    setLoadingClient(true);
    Promise.all([
      tools.host_getClient({ id: clientId }),
      tools.host_listClientDocuments({ id: clientId }),
    ]).then(([c, d]) => {
      setClient(c);
      const reviewable = (d.data || []).filter(
        (doc) => doc.status === "received" || doc.status === "needs_review"
      );
      setDocs(reviewable);
      setLoadingClient(false);
    });
  }, [clientId]);

  const reviewable = docs;

  const setAction = (docId, action) =>
    setActions((prev) => ({ ...prev, [docId]: action }));
  const setNote = (docId, val) =>
    setNotes((prev) => ({ ...prev, [docId]: val }));

  const submit = async (doc) => {
    const action = actions[doc.id];
    if (!action) return;
    setPhases((prev) => ({ ...prev, [doc.id]: "sending" }));
    const body = {
      action,
      fileName: doc.fileName || doc.name || "",
      ...(action === "reject" ? { reason: notes[doc.id] || "" } : {}),
    };
    const result = await tools.host_setDocumentStatus({ id: clientId, docId: doc.id, body });
    const nextPhase =
      result && result.status === "pending-approval" ? "awaiting" : "done";
    setPhases((prev) => ({ ...prev, [doc.id]: nextPhase }));
    if (nextPhase === "done") {
      setDocs((prev) => prev.filter((d) => d.id !== doc.id));
    }
    if (notes[doc.id] && action === "reject") {
      await tools.host_sendClientMessage({
        id: clientId,
        body: { body: notes[doc.id], author: "firm" },
      });
    }
  };

  const statusColor = (s) => {
    if (s === "received") return "var(--vendo-color-accent)";
    if (s === "needs_review") return "#b07a00";
    return "var(--vendo-color-muted)";
  };

  const statusLabel = (s) => {
    if (s === "received") return "Received";
    if (s === "needs_review") return "Needs review";
    return s;
  };

  return (
    <div style={{ fontFamily: "var(--vendo-font-family)", color: "var(--vendo-color-text)", display: "grid", gap: 20 }}>
      {/* Client picker */}
      <div style={{ background: "var(--vendo-color-surface)", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-medium)", padding: 20 }}>
        <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 8, color: "var(--vendo-color-muted)", textTransform: "uppercase", letterSpacing: "0.04em" }}>Select client</div>
        <select
          value={clientId}
          onChange={(e) => setClientId(e.target.value)}
          style={{ width: "100%", padding: "9px 12px", borderRadius: "var(--vendo-radius-small)", border: "1px solid var(--vendo-color-border)", background: "var(--vendo-color-background)", color: "var(--vendo-color-text)", fontFamily: "var(--vendo-font-family)", fontSize: 15 }}
        >
          <option value="">Choose a client…</option>
          {clients.map((c) => (
            <option key={c.id} value={c.id}>{c.name}{c.entityType ? ` — ${c.entityType}` : ""}</option>
          ))}
        </select>
      </div>

      {/* Client summary */}
      {client && (
        <div style={{ background: "var(--vendo-color-surface)", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-medium)", padding: 20, display: "flex", gap: 32, alignItems: "center", flexWrap: "wrap" }}>
          <div>
            <div style={{ fontSize: 18, fontWeight: 700 }}>{client.name}</div>
            <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", marginTop: 2 }}>{client.entityType || ""}{client.assignedStaff ? ` · ${client.assignedStaff}` : ""}</div>
          </div>
          <div style={{ display: "flex", gap: 24, flexWrap: "wrap" }}>
            <div style={{ textAlign: "center" }}>
              <div style={{ fontSize: 22, fontWeight: 700 }}>{reviewable.length}</div>
              <div style={{ fontSize: 12, color: "var(--vendo-color-muted)" }}>Awaiting review</div>
            </div>
            {client.filingDeadline && (
              <div style={{ textAlign: "center" }}>
                <div style={{ fontSize: 15, fontWeight: 600 }}>{new Date(client.filingDeadline).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}</div>
                <div style={{ fontSize: 12, color: "var(--vendo-color-muted)" }}>Filing deadline</div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Loading */}
      {loadingClient && (
        <div style={{ color: "var(--vendo-color-muted)", fontSize: 14, padding: "12px 0" }}>Loading documents…</div>
      )}

      {/* Empty state */}
      {!loadingClient && clientId && reviewable.length === 0 && (
        <div style={{ background: "var(--vendo-color-surface)", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-medium)", padding: 32, textAlign: "center", color: "var(--vendo-color-muted)", fontSize: 15 }}>
          No documents awaiting review for this client — nothing to action right now.
        </div>
      )}

      {/* Document cards */}
      {!loadingClient && reviewable.map((doc) => {
        const phase = phases[doc.id];
        const action = actions[doc.id];
        const isDone = phase === "done";
        const isAwaiting = phase === "awaiting";
        const isSending = phase === "sending";

        return (
          <div key={doc.id} style={{ background: "var(--vendo-color-surface)", border: `1px solid ${isDone ? "var(--vendo-color-border)" : "var(--vendo-color-border)"}`, borderRadius: "var(--vendo-radius-medium)", padding: 20, opacity: isDone ? 0.5 : 1, display: "grid", gap: 14 }}>
            {/* Doc header */}
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 12, flexWrap: "wrap" }}>
              <div>
                <div style={{ fontWeight: 600, fontSize: 15 }}>{doc.name || doc.type || "Document"}</div>
                {doc.fileName && (
                  <div style={{ fontSize: 13, color: "var(--vendo-color-muted)", marginTop: 2 }}>File: {doc.fileName}</div>
                )}
                {doc.uploadedAt && (
                  <div style={{ fontSize: 12, color: "var(--vendo-color-muted)", marginTop: 2 }}>
                    Uploaded {new Date(doc.uploadedAt).toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })}
                  </div>
                )}
              </div>
              <span style={{ display: "inline-flex", alignItems: "center", gap: 6, fontSize: 12, fontWeight: 600, padding: "4px 10px", borderRadius: 99, background: doc.status === "needs_review" ? "#fef3c7" : "#e8f0fe", color: statusColor(doc.status) }}>
                <span style={{ width: 6, height: 6, borderRadius: "50%", background: statusColor(doc.status), display: "inline-block" }}/>
                {statusLabel(doc.status)}
              </span>
            </div>

            {/* Action buttons */}
            {!isDone && !isAwaiting && (
              <div style={{ display: "flex", gap: 10 }}>
                <button
                  onClick={() => setAction(doc.id, "verify")}
                  style={{ padding: "8px 18px", borderRadius: "var(--vendo-radius-small)", border: `2px solid ${action === "verify" ? "var(--vendo-color-accent)" : "var(--vendo-color-border)"}`, background: action === "verify" ? "var(--vendo-color-accent)" : "var(--vendo-color-surface)", color: action === "verify" ? "var(--vendo-color-accent-text)" : "var(--vendo-color-text)", fontFamily: "var(--vendo-font-family)", fontSize: 14, fontWeight: 600, cursor: "pointer" }}
                >
                  ✓ Verify
                </button>
                <button
                  onClick={() => setAction(doc.id, "reject")}
                  style={{ padding: "8px 18px", borderRadius: "var(--vendo-radius-small)", border: `2px solid ${action === "reject" ? "var(--vendo-color-danger)" : "var(--vendo-color-border)"}`, background: action === "reject" ? "#fef2f2" : "var(--vendo-color-surface)", color: action === "reject" ? "var(--vendo-color-danger)" : "var(--vendo-color-text)", fontFamily: "var(--vendo-font-family)", fontSize: 14, fontWeight: 600, cursor: "pointer" }}
                >
                  ✕ Reject
                </button>
              </div>
            )}

            {/* Note field — always shown for reject, optional for verify */}
            {!isDone && !isAwaiting && action === "reject" && (
              <div style={{ display: "grid", gap: 6 }}>
                <label style={{ fontSize: 13, fontWeight: 600, color: "var(--vendo-color-muted)" }}>Reason for rejection (sent to client)</label>
                <textarea
                  rows={3}
                  placeholder="e.g. The W-2 is missing page 2. Please re-upload the complete document."
                  value={notes[doc.id] || ""}
                  onChange={(e) => setNote(doc.id, e.target.value)}
                  style={{ width: "100%", padding: "9px 12px", borderRadius: "var(--vendo-radius-small)", border: "1px solid var(--vendo-color-border)", fontFamily: "var(--vendo-font-family)", fontSize: 14, color: "var(--vendo-color-text)", background: "var(--vendo-color-background)", resize: "vertical", boxSizing: "border-box" }}
                />
              </div>
            )}

            {/* Submit */}
            {!isDone && !isAwaiting && action && (
              <div>
                <button
                  onClick={() => submit(doc)}
                  disabled={isSending || (action === "reject" && !notes[doc.id]?.trim())}
                  style={{ padding: "9px 22px", borderRadius: "var(--vendo-radius-small)", border: "none", background: action === "reject" ? "var(--vendo-color-danger)" : "var(--vendo-color-accent)", color: "var(--vendo-color-accent-text)", fontFamily: "var(--vendo-font-family)", fontSize: 14, fontWeight: 700, cursor: isSending ? "not-allowed" : "pointer", opacity: (isSending || (action === "reject" && !notes[doc.id]?.trim())) ? 0.5 : 1 }}
                >
                  {isSending ? "Submitting…" : action === "verify" ? "Confirm verify" : "Confirm rejection"}
                </button>
                {action === "reject" && !notes[doc.id]?.trim() && (
                  <span style={{ marginLeft: 12, fontSize: 12, color: "var(--vendo-color-muted)" }}>A reason is required before rejecting.</span>
                )}
              </div>
            )}

            {/* Awaiting approval */}
            {isAwaiting && (
              <div style={{ fontSize: 14, color: "var(--vendo-color-muted)", fontStyle: "italic" }}>Awaiting your approval…</div>
            )}

            {/* Done */}
            {isDone && (
              <div style={{ fontSize: 14, color: "var(--vendo-color-muted)" }}>
                {action === "verify" ? "✓ Verified" : "✕ Rejected — client notified"}
              </div>
            )}
          </div>
        );
      })}

      {/* No client selected */}
      {!clientId && (
        <div style={{ background: "var(--vendo-color-surface)", border: "1px solid var(--vendo-color-border)", borderRadius: "var(--vendo-radius-medium)", padding: 32, textAlign: "center", color: "var(--vendo-color-muted)", fontSize: 15 }}>
          Select a client above to begin reviewing their uploaded documents.
        </div>
      )}
    </div>
  );
}
